inline bool VerifyEncodingParams(::flatbuffers::Verifier &verifier, const void *obj, EncodingParams type) {
  switch (type) {
    case EncodingParams::NONE: {
      return true;
    }
    case EncodingParams::RawEncodingParams: {
      auto ptr = reinterpret_cast<const vdb::schema::RawEncodingParams *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EncodingParams::BitpackEncodingParams: {
      auto ptr = reinterpret_cast<const vdb::schema::BitpackEncodingParams *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EncodingParams::DictEncodingParams: {
      auto ptr = reinterpret_cast<const vdb::schema::DictEncodingParams *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EncodingParams::RleEncodingParams: {
      auto ptr = reinterpret_cast<const vdb::schema::RleEncodingParams *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EncodingParams::VarintEncodingParams: {
      auto ptr = reinterpret_cast<const vdb::schema::VarintEncodingParams *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EncodingParams::DeltaEncodingParams: {
      auto ptr = reinterpret_cast<const vdb::schema::DeltaEncodingParams *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EncodingParams::FsstEncodingParams: {
      auto ptr = reinterpret_cast<const vdb::schema::FsstEncodingParams *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EncodingParams::FrameOfRefEncodingParams: {
      auto ptr = reinterpret_cast<const vdb::schema::FrameOfRefEncodingParams *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case EncodingParams::RaBitQEncodingParams: {
      auto ptr = reinterpret_cast<const vdb::schema::RaBitQEncodingParams *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

inline bool VerifyEncodingParamsVector(::flatbuffers::Verifier &verifier, const ::flatbuffers::Vector<::flatbuffers::Offset<void>> *values, const ::flatbuffers::Vector<EncodingParams> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (::flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyEncodingParams(
        verifier,  values->Get(i), types->GetEnum<EncodingParams>(i))) {
      return false;
    }
  }
  return true;
}

